INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '下列关于虚电路网络的叙述中，错误的是 (21) 。 虚电路网络不像电路交换那样为每个连接分配固定的带宽。虚电路网络通常基于需要动态地分配带宽 (尽管它会为每个虚电路维护状态信息) 。 | 单选题', '["A. 虚电路建立后可以确保数据分组按序交付", "B. 路由选择在建立虚电路时进行", "D. 数据分组转发的依据是虚电路标识号 (VCID)"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '如图所示，N个用户共享一个1Gb/s的链路，假设每个用户需要100Mb/s的带宽，如果采用电路交换方式，该系统仅支持10个用户。若采用分组交换，假设有35个用户，用户活跃的平均概率均为 10%，则同时有超过10个用户活跃的概率约为 (9) 。 | 单选题', '["A. 0.2857%", "B. 0%", "C. 0.0004%", "D. 0.010%"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
