INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '使用AdHoc模式组网，可采用的路由协议不包括 (13) 。 在AdHoc模式下，网络通常由一组独立的设备 (节点) 组成，这些设备不依赖固定的基础设施。常见的路由协议包括基于位置的路由协议、分层路由协议和平面路由协议，而域闻路由协议通常 用于结构化的网络环境 (如互联网) ，不适合AdHoc网络。 | 单选题', '["A. 基于位置路由协议", "B. 分层路由协议", "C. 域间路由协议", "D. 平面路由协议"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
