INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '75, An advanced persistent threat (APT) is a covert (71) attack on a computer network where the attacker gains and maintains (72) access to the targeted network and remains undetected for a significant period. An APT is a sophisticated, long-term and (73) attack, usually orchestrated by nation-state groups, or well-organized criminal enterprises. During the time between infection and remediation the hacker will often monitor, intercept, and relay information and sensitive data. The intention of an APT is usually to (74) or steal data rather than cause a network outage, denial of service or infect systems with malware. APTs often use social engineering tactics or exploit security (75) in networks, applications or files to plant malware on target systems. A successful advanced persistent threat can be extremely effective and beneficial to the attacker.', '["B. cyber", "C. virtual", "D. military", "B. authorized"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
